private static final Logger log = LoggerFactory.getLogger(CompleteTaskUseCase.class);

public Optional<TaskCompletionResult> execute(Long taskId) {
    log.info("Iniciando conclusão de tarefa", 
        kv("taskId", taskId));

    Optional<Task> taskOpt = repository.findById(taskId);
    if (taskOpt.isEmpty()) {
        log.warn("Tarefa não encontrada", 
            kv("taskId", taskId));
        return Optional.empty();
    }

    Task task = taskOpt.get();
    String validationError = policy.validate(task);
    if (validationError != null) {
        log.warn("Validação falhou", 
            kv("taskId", taskId),
            kv("error", validationError));
        return Optional.empty();
    }

    try {
        Task completed = service.execute(task);
        repository.save(completed);
        log.info("Tarefa concluída com sucesso", 
            kv("taskId", taskId),
            kv("completedAt", completed.completedAt()));
        return Optional.of(new TaskCompletionResult(completed));
    } catch (Exception e) {
        log.error("Erro ao concluir tarefa", 
            kv("taskId", taskId), e);
        throw new TaskCompletionException("Falha ao concluir tarefa", e);
    }
}
```

