@ExtendWith(MockitoExtension.class)
class CompleteTaskUseCaseTest {
    @Mock private TaskRepository repository;
    @Mock private TaskPolicy policy;
    @Mock private TaskCompletionService service;

    private CompleteTaskUseCase useCase;

    @BeforeEach
    void setUp() {
        useCase = new CompleteTaskUseCase(repository, policy, service);
    }

    @Test
    void deveRetornarVazioQuandoTarefaNaoEncontrada() {
        when(repository.findById(1L)).thenReturn(Optional.empty());

        Optional<TaskCompletionResult> result = useCase.execute(1L);

        assertThat(result).isEmpty();
        verify(repository).findById(1L);
        verifyNoInteractions(policy, service);
    }
}
```

