#### **Semana 2, Dia 3-5: Testes de TaskPolicy (6h)**

**Tarefa 5.1: Testar validação de status**
```java
class TaskPolicyTest {
    private TaskPolicy policy;
    private Clock fixedClock;

    @BeforeEach
    void setUp() {
        fixedClock = Clock.fixed(Instant.parse("2024-01-15T10:00:00Z"), ZoneOffset.UTC);
        policy = new TaskPolicy(fixedClock);
    }

    @Test
    void deveRejeitarTarefaJaConcluida() {
        Task task = new Task(1L, "Tarefa", TaskStatus.DONE, "owner", 8, 
            LocalDateTime.now(fixedClock), null);

        String error = policy.validate(task);

        assertThat(error).isEqualTo("TASK_ALREADY_COMPLETED");
    }

    @Test
    void deveRejeitarTarefaCancelada() {
        Task task = new Task(1L, "Tarefa", TaskStatus.CANCELLED, "owner", 8, 
            LocalDateTime.now(fixedClock), null);

        String error = policy.validate(task);

        assertThat(error).isEqualTo("TASK_CANCELLED");
    }

    @Test
    void deveRejeitarTarefaSemOwner() {
        Task task = new Task(1L, "Tarefa", TaskStatus.IN_PROGRESS, null, 8, 
            LocalDateTime.now(fixedClock), null);

        String error = policy.validate(task);

        assertThat(error).isEqualTo("TASK_WITHOUT_OWNER");
    }

    @Test
    void deveRejeitarTarefaComEstimativaInvalida() {
        Task task = new Task(1L, "Tarefa", TaskStatus.IN_PROGRESS, "owner", 0, 
            LocalDateTime.now(fixedClock), null);

        String error = policy.validate(task);

        assertThat(error).isEqualTo("TASK_INVALID_ESTIMATE");
    }

    @Test
    void deveAceitarTarefaValida() {
        Task task = new Task(1L, "Tarefa", TaskStatus.IN_PROGRESS, "owner", 8, 
            LocalDateTime.now(fixedClock), null);

        String error = policy.validate(task);

        assertThat(error).isNull();
    }
}
```

