        LocalDateTime.now(), null);
    Task completed = new Task(1L, "Tarefa", TaskStatus.DONE, "owner", 8, 
        LocalDateTime.now(), LocalDateTime.now());
    when(repository.findById(1L)).thenReturn(Optional.of(task));
    when(policy.validate(task)).thenReturn(null);
    when(service.execute(task)).thenReturn(completed);
    when(repository.save(completed)).thenReturn(completed);

    Optional<TaskCompletionResult> result = useCase.execute(1L);

    assertThat(result).isPresent();
    assertThat(result.get().task()).isEqualTo(completed);
    verify(repository).findById(1L);
    verify(policy).validate(task);
    verify(service).execute(task);
    verify(repository).save(completed);
